-- Test script for development.

CREATE VIEW foo AS
    SELECT a1::INTEGER AS x, (random() * 100)::INTEGER AS y, (random() * 100)::INTEGER as c, (random() * 100)::INTEGER as d, (random() * 100)::INTEGER as e, (random() * 100)::INTEGER as f, (random() * 100)::INTEGER as g, (random() * 100)::INTEGER as h
    FROM generate_series(0, 1000000) AS a(a1);

VIZ foo USING LINE(
    title = 'Line Chart',
    pos = (r = 4, c = 0, w = 6, h = 4)
);
VIZ foo USING TABLE (
    pos = (r = 0, c = 0, w = 12, h = 4)
);
